            machine_id = int(operation.machine_id)
            latest_start = max(0, horizon - duration)
            start = model.NewIntVar(0, latest_start, f"s_{job_id}_{op_index}")
            end = model.NewIntVar(duration, horizon, f"e_{job_id}_{op_index}")
