        next_op = [0] * num_jobs
        job_ready = [0] * num_jobs
        machine_ready = [0] * num_machines
        starts = {}
        ends = {}
        sequences = [[] for _ in range(num_machines)]
        unscheduled = sum(len(job) for job in jobs)

        while unscheduled:
            best_ect = None
            critical_machine = None
            for j in range(num_jobs):
                k = next_op[j]
                if k >= len(jobs[j]):
                    continue
                m, p = jobs[j][k]
                est = max(job_ready[j], machine_ready[m])
                ect = est + p
                if best_ect is None or ect < best_ect:
                    best_ect = ect
                    critical_machine = m

            chosen = None
            chosen_key = None
            for j in range(num_jobs):
                k = next_op[j]
                if k >= len(jobs[j]):
                    continue
                m, p = jobs[j][k]
                if m != critical_machine:
                    continue
                est = max(job_ready[j], machine_ready[m])
                if est >= best_ect:
                    continue
                ect = est + p
                key = priority_key(j, k, est, ect, rule, noise)
                if chosen_key is None or key < chosen_key:
                    chosen_key = key
                    chosen = j

            if chosen is None:
                for j in range(num_jobs):
                    k = next_op[j]
                    if k < len(jobs[j]):
                        chosen = j
                        break

            j = chosen
            k = next_op[j]
            m, p = jobs[j][k]
            st = max(job_ready[j], machine_ready[m])
            en = st + p
            starts[(j, k)] = st
            ends[(j, k)] = en
            job_ready[j] = en
            machine_ready[m] = en
            next_op[j] += 1
            sequences[m].append(j)
            unscheduled -= 1

        return max(job_ready) if job_ready else 0, sequences, starts, ends

    best = None
    for rule in range(11):
        cand = run(rule, 0.0)
        if best is None or cand[0] < best[0]:
            best = cand

